import heapq
from typing import List

class Solution:
    def matrixSum(self, nums: List[List[int]]) -> int:
        heaps = []
        for row in nums:
            heap = [-x for x in row]
            heapq.heapify(heap)
            heaps.append(heap)

        total_score = 0
        while any(heaps):
            current_max_of_row_maxes = float('-inf')
            for i in range(len(heaps)):
                if heaps[i]:
                    val = -heapq.heappop(heaps[i])
                    if val > current_max_of_row_maxes:
                        current_max_of_row_maxes = val
            total_score += current_max_of_row_maxes

        return total_score

class Solution:
    def maximumOr(self, nums: List[int], k: int) -> int:
        res = 0
        for x in nums:
            res |= x

        for i in range(45, -1, -1):
            if (res >> i) & 1:
                continue

            best_res = -1
            for x in nums:
                for shift in range(1, k + 1):
                    shifted = x << shift
                    if (shifted >> i) & 1:
                        # Check if bits > i are preserved
                        # The bits > i in (shifted | res) must be the same as in res
                        if (shifted | res) & ~((1 << (i + 1)) - 1) == res:
                            if (shifted | res) > best_res:
                                best_res = (shifted | res)

            if best_res != -1:
                res = best_res
        return res

class Solution:
    def maxStrength(self, nums: List[int]) -> int:
        positives = [x for x in nums if x > 0]
        negatives = sorted([x for x in nums if x < 0])
        zeros = [x for x in nums if x == 0]

        if not positives:
            if len(negatives) >= 2:
                # Product of all negatives if even, else all but the largest
                res = 1
                limit = len(negatives) if len(negatives) % 2 == 0 else len(negatives) - 1
                for i in range(limit):
                    res *= negatives[i]
                return res
            elif len(negatives) == 1:
                return negatives[0] if not zeros else 0
            else:
                return 0
        else:
            res = 1
            for x in positives:
                res *= x

            num_neg = len(negatives)
            limit = num_neg if num_neg % 2 == 0 else num_neg - 1
            for i in range(limit):
                res *= negatives[i]
            return res

class Solution:
    def minExtraChar(self, s: str, dictionary: List[str]) -> int:
        n = len(s)
        # dp[i] will store the minimum extra characters for s[0:i]
        dp = [0] * (n + 1)

        # Initialize dp array with the maximum possible extra characters
        # (each character being extra)
        for i in range(1, n + 1):
            dp[i] = i

        # Convert dictionary to a set for O(1) lookups
        word_set = set(dictionary)

        # Fill the dp table
        for i in range(1, n + 1):
            # Option 1: The current character s[i-1] is an extra character
            dp[i] = dp[i-1] + 1

            # Option 2: Try to find a word in the dictionary ending at i
            for j in range(i):
                if s[j:i] in word_set:
                    dp[i] = min(dp[i], dp[j])

        return dp[n]

class Solution:
    def buyChoco(self, prices: List[int], money: int) -> int:
        # Sort the prices to easily find the two cheapest chocolates
        prices.sort()

        # The two cheapest chocolates are at index 0 and 1
        min_sum = prices[0] + prices[1]

        # Check if we can afford the two cheapest chocolates
        if min_sum <= money:
            return money - min_sum
        else:
            # If we can't afford the two cheapest, we can't afford any two
            return money

class Solution:
    def count(self, num1: str, num2: str, min_sum: int, max_sum: int) -> int:
        MOD = 10**9 + 7

        def count_upto(n_str: str) -> int:
            memo = {}
            def dp(pos, current_sum, is_less):
                if current_sum > max_sum:
                    return 0
                if pos == len(n_str):
                    return 1 if min_sum <= current_sum <= max_sum else 0

                state = (pos, current_sum, is_less)
                if state in memo:
                    return memo[state]

                res = 0
                limit = int(n_str[pos]) if not is_less else 9
                for digit in range(limit + 1):
                    res = (res + dp(pos + 1, current_sum + digit, is_less or (digit < limit))) % MOD

                memo[state] = res
                return res

            return dp(0, 0, False)

        ans2 = count_upto(num2)
        ans1 = count_upto(str(int(num1) - 1)) if int(num1) > 0 else 0
        return (ans2 - ans1 + MOD) % MOD

class Solution:
    def colorTheArray(self, n: int, queries: List[List[int]]) -> List[int]:
        nums = [0] * n
        ans = []
        current_count = 0

        for index, color in queries:
            old_color = nums[index]

            # Remove contribution of the old color
            if old_color != 0:
                if index > 0 and nums[index-1] == old_color:
                    current_count -= 1
                if index < n - 1 and nums[index+1] == old_color:
                    current_count -= 1

            # Update the color
            nums[index] = color

            # Add contribution of the new color
            if color != 0:
                if index > 0 and nums[index-1] == color:
                    current_count += 1
                if index < n - 1 and nums[index+1] == color:
                    current_count += 1

            ans.append(current_count)

        return ans

class Solution:
    def semiOrderedPermutation(self, nums: List[int]) -> int:
        n = len(nums)
        pos1 = -1
        posN = -1

        for i in range(n):
            if nums[i] == 1:
                pos1 = i
            if nums[i] == n:
                posN = i

        # Distance for 1 to reach index 0
        dist1 = pos1
        # Distance for n to reach index n-1
        distN = (n - 1) - posN

        # If 1 is to the right of n, they must cross each other.
        # One swap will move both 1 and n closer to their targets.
        if pos1 > posN:
            return dist1 + distN - 1
        else:
            return dist1 + distN
